import { useParams } from "react-router-dom";
import { useEffect, useState} from "react";
import axios from "axios";
import config from "../../config.json"

import MainBtns from "../../Components/Buttons/MainBtns";
import CourseCard from "../../Components/CourseCard";

function UserPage() {
  const {id} = useParams()
  const [image, setImage] = useState(null);
  const [user, setUser] = useState();
  const [userCourses, setCourses] = useState([]);

  useEffect(() => {

    /*fetch(`/Files/Tests/UserCoursesTest.json`, { cache: "no-store" })
      .then(res => {
        if (!res.ok) throw new Error("Ничего не найдено");
        return res.json();
      }).then(datas => setCourses(datas))

      fetch(`/Files/Tests/UserTest.json`, { cache: "no-store" })
      .then(res => {
        if (!res.ok) throw new Error("Ничего не найдено");
        return res.json();
      }).then(datas => setUser(datas))

      fetch("/Files/discord server icon.gif", { cache: "no-store" })
  .then(res => {
    if (!res.ok) throw new Error("Ничего не найдено");
    return res.blob();
  })
    .then(blob => {
    const url = URL.createObjectURL(blob);
    setImage(url);
  })
    .catch(err => console.error(err));
*/

  useEffect(() => {
  axios.get(config.BaseURL +"/me", {
    withCredentials: true
  })
  .then((res) => {setUser(res?.data);console.log(res)})
  .catch((err) => {console.log(err)})
}, [])
  }, []);
 


  return (
    <div className="user-page">
      <div className="black-container">
        <div className="black-container-content">
          <p>{user?.role}</p>
          <h1>{user?.name}</h1>
        </div>
      </div>
      <div className="user-info-container">
        <img src={image} alt=""/>
        <MainBtns Text={"Редактировать"} Style={"null-btn"} NavigateTo={"/settings/profile"}/>
      </div>
      <div style={{marginLeft:"5%", marginTop:"2%"}}>
        <h2 style={{marginBottom:"20px"}}>Courses</h2>
        <ul className="courses-list">
          {userCourses.map((item,index)=>(
          <li>
            <CourseCard key={index} courseInfo={item}/>
          </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default UserPage;
